function has_close_elements(numbers, threshold) {
    // Sort the array to easily find closest elements
    const sorted = [...numbers].sort((a, b) => a - b);

    for (let i = 0; i < sorted.length - 1; i++) {
        if (sorted[i + 1] - sorted[i] < threshold) {
            return true;
        }
    }

    return false;
}
