```javascript
function sort_third(l) {
    // Extract elements at indices divisible by 3 (0, 3, 6, ...)
    const thirdElements = [];
    for (let i = 0; i < l.length; i += 3) {
        thirdElements.push(l[i]);
    }

    // Sort these elements
    thirdElements.sort((a, b) => a - b);

    // Create result array as a copy of input
    const result = [...l];

    // Place sorted elements back at indices divisible by 3
    let j = 0;
    for (let i = 0; i < l.length; i += 3) {
        result[i] = thirdElements[j++];
    }

    return result;
}
