```javascript
function triangle_area(a, b, c) {
    // Check if the sides form a valid triangle
    if (a + b <= c || a + c <= b || b + c <= a) {
        return -1;
    }

    // Calculate the semi-perimeter
    const s = (a + b + c) / 2;

    // Use Heron's formula to calculate the area
    const area = Math.sqrt(s * (s - a) * (s - b) * (s - c));

    // Round to 2 decimal points
    return Math.round(area * 100) / 100;
}
```

```javascript
function will_it_fly(q, w) {
    // Check if q is a palindrome (balanced)
    let isBalanced = true;
    for (let i = 0; i < Math.floor(q.length / 2); i++) {
        if (q[i] !== q[q.length - 1 - i]) {
            isBalanced = false;
            break;
        }
    }

    // Calculate the sum of elements
    let sum = q.reduce((acc, val) => acc + val, 0);

    // Return true if balanced and sum <= w
    return isBalanced && sum <= w;
}
