function is_simple_power(x, n) {
    // Handle edge cases
    if (x === 1) {
        return true; // n^0 = 1 for any n != 0, and 0^0 is typically undefined but we'll say true for x=1
    }

    if (n === 0) {
        // 0^k = 0 for k > 0, so only x=0 could be a power, but 0^0 is ambiguous
        return false;
    }

    if (n === 1) {
        // 1^k = 1 for any k, so only x=1 is a power of 1
        return x === 1;
    }

    if (n === -1) {
        // (-1)^k alternates between -1 and 1
        return x === 1 || x === -1;
    }

    let current = 1;
    while (Math.abs(current) < Math.abs(x)) {
        current *= n;
    }

    return current === x;
}
