function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }

    // Numbers that start with 1: 1 followed by any (n-1) digits
    // Count = 10^(n-1)
    const startsWithOne = Math.pow(10, n - 1);

    // Numbers that end with 1: any digit from 1-9 for first position, 
    // any digits for middle positions, and last digit is 1
    // Count = 9 * 10^(n-2)
    const endsWithOne = 9 * Math.pow(10, n - 2);

    // Numbers that both start AND end with 1: 1 followed by (n-2) any digits, then 1
    // Count = 10^(n-2)
    const bothStartAndEndWithOne = Math.pow(10, n - 2);

    // Use inclusion-exclusion principle
    return startsWithOne + endsWithOne - bothStartAndEndWithOne;
}
