            const newCode = (code + shift) % 26;
            result += String.fromCharCode(newCode + 97);
        } else if (char >= 'A' && char <= 'Z') {
            // Uppercase letter
            const code = char.charCodeAt(0) - 65; // 0-25
            const newCode = (code + shift) % 26;
            result += String.fromCharCode(newCode + 65);
        } else {
            // Non-alphabetic character, keep as is
            result += char;
