    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);
    const consonants = new Set();
    for (let i = 65; i <= 90; i++) {
        if (!vowels.has(String.fromCharCode(i))) {
            consonants.add(String.fromCharCode(i));
        }
    }
    for (let i = 97; i <= 122; i++) {
        if (!vowels.has(String.fromCharCode(i))) {
            consonants.add(String.fromCharCode(i));
        }
    }

    // We need to find the closest vowel from the right side that stands between two consonants.
    // "Stands between two consonants" means the pattern is: consonant, vowel, consonant
    // We scan from right to left (excluding first and last characters)

    for (let i = word.length - 2; i >= 1; i--) {
        const prevChar = word[i - 1];
        const currChar = word[i];
        const nextChar = word[i + 1];

        if (consonants.has(prevChar) && vowels.has(currChar) && consonants.has(nextChar)) {
            return currChar;
