    // Returns the minimum balance encountered and the final balance
    function getBalanceInfo(s) {
        let minBalance = 0;
        let currentBalance = 0;
        for (let char of s) {
            if (char === '(') {
                currentBalance++;
            } else {
                currentBalance--;
            }
            minBalance = Math.min(minBalance, currentBalance);
        }
        return { minBalance, finalBalance: currentBalance };
    }

    const info1 = getBalanceInfo(lst[0]);
    const info2 = getBalanceInfo(lst[1]);

    // Check if concatenating lst[0] + lst[1] is valid
    // For lst[0] + lst[1] to be valid:
    // 1. The combined final balance must be 0
    // 2. At any point, the running balance must not drop below 0

    // When we concatenate A + B:
    // - The balance starts at 0, goes through A's balances (relative to start)
    // - Then continues with B's balances (relative to A's final balance)

    // For A + B to be valid:
    // - info1.finalBalance + info2.finalBalance === 0
    // - info1.minBalance >= 0 (A itself never goes negative)
    // - For every point in B, the running balance (info1.finalBalance + info2's running balance from start of B) >= 0
    //   This means: info1.finalBalance + info2.minBalance >= 0

    const totalBalance = info1.finalBalance + info2.finalBalance;

    if (totalBalance !== 0) {
        return "No";
    }

    // Check A + B order
    const abValid = info1.minBalance >= 0 && (info1.finalBalance + info2.minBalance >= 0);

    // Check B + A order
    const baValid = info2.minBalance >= 0 && (info2.finalBalance + info1.minBalance >= 0);

    if (abValid || baValid) {
        return "Yes";
    }

    return "No";
}
