function intersection(interval1, interval2) {
    // Helper function to check if a number is prime
    function isPrime(n) {
        if (n <= 1) return false;
        if (n <= 3) return true;
        if (n % 2 === 0 || n % 3 === 0) return false;
        for (let i = 5; i * i <= n; i += 6) {
            if (n % i === 0 || n % (i + 2) === 0) return false;
        }
        return true;
    }

    // Calculate the intersection of two intervals
    const start = Math.max(interval1[0], interval2[0]);
    const end = Math.min(interval1[1], interval2[1]);

    // If there's no intersection, return "NO"
    if (start > end) {
        return "NO";
    }

    // Calculate the length of the intersection
    // The length is defined as end - start for closed intervals
    // For example, intersection (2, 3) has length 1 (3-2=1)
    const length = end - start;

    // Check if the length is a prime number
    if (isPrime(length)) {
        return "YES";
    } else {
        return "NO";
    }
}
