function tri(n) {
    if (n < 0) return [];

    // The problem says "first n + 1 numbers", and the example tri(3) returns [1, 3, 2, 8]
    // Let's check: indices 0, 1, 2, 3 -> 4 elements for n=3.
    // But wait, the definition says tri(1) = 3, tri(2) = 2, tri(4) = 3, tri(3) = 8.
    // The example output is [1, 3, 2, 8]. So index 0 is 1? Let's re-read carefully.

    // "tri(1) = 3"
    // "tri(2) = 2"
    // "tri(4) = 3"
    // "tri(3) = 8"
    // Output for tri(3) is [1, 3, 2, 8]

    // It seems like the sequence starts at index 0 with value 1, then:
    // tri(0) = 1 (implied, not stated but present in output)
    // tri(1) = 3
    // tri(2) = 2
    // tri(3) = 8

    // Let's verify the recurrence for n=3 (odd):
    // tri(3) = tri(2) + tri(1) + tri(4)
    // We need tri(4). For n=4 (even): tri(4) = 1 + 4/2 = 3. Correct.
    // So tri(3) = 2 + 3 + 3 = 8. Correct.

    // What about tri(0)? The problem says "non-negative integer n".
    // The example output starts with 1. Let's assume tri(0) = 1.

    // Let's build the array up to index n.
    const result = new Array(n + 1);

    // Base cases
    if (n >= 0) result[0] = 1;
    if (n >= 1) result[1] = 3;

    for (let i = 2; i <= n; i++) {
        if (i % 2 === 0) {
            // Even case: tri(n) = 1 + n / 2
            result[i] = 1 + i / 2;
        } else {
            // Odd case: tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
            // But wait, tri(n+1) depends on a future value!
            // For n=3: tri(3) = tri(2) + tri(1) + tri(4)
            // We need tri(4) to compute tri(3). So we might need to compute ahead.

            // Let's think about this differently. The recurrence for odd n depends on tri(n+1).
            // tri(n+1) is even, so tri(n+1) = 1 + (n+1)/2.
            // So for odd i: tri(i) = tri(i-1) + tri(i-2) + (1 + (i+1)/2)

            const triNextEven = 1 + (i + 1) / 2;
            result[i] = result[i - 1] + result[i - 2] + triNextEven;
        }
    }

    return result;
}
