    // So the condition is: does there exist i < j < k < l such that s[i]='[', s[j]='[', s[k]=']', s[l]=']'?

    let firstOpen = -1;
    let secondOpen = -1;
    let firstClose = -1;
    let secondClose = -1;

    for (let i = 0; i < string.length; i++) {
        if (string[i] === '[') {
            if (firstOpen === -1) {
                firstOpen = i;
            } else if (secondOpen === -1) {
                secondOpen = i;
            }
        } else {
            if (secondOpen !== -1 && firstClose === -1) {
                firstClose = i;
            } else if (firstClose !== -1) {
                // We have found our pattern: firstOpen < secondOpen < firstClose < i
                return true;
            }
        }
    }

    return false;
}
