function check_if_last_char_is_a_letter(txt) {
    // Trim trailing spaces to handle cases where the string ends with spaces
    const trimmed = txt.trimEnd();

    // If the string is empty after trimming, return false
    if (trimmed.length === 0) {
        return false;
    }

    // Get the last character
    const lastChar = trimmed[trimmed.length - 1];

    // Check if it's an alphabetical character
    if (!/^[a-zA-Z]$/.test(lastChar)) {
        return false;
    }

    // If the string has only one character, it's not part of a word separated by space
    // But we need to check if it's "not a part of a word" meaning it should be isolated by spaces or at the start/end without being attached to other letters.
    // Actually, re-reading: "is not a part of a word" means the last character should be a standalone letter, i.e., preceded by a space (or be the only character in the string).

    if (trimmed.length === 1) {
        return true;
    }

    // Check if the character before the last one is a space
    const secondLastChar = trimmed[trimmed.length - 2];

    // If the second to last character is a space, then the last character is isolated (not part of a word)
    return secondLastChar === ' ';
}
