function order_by_points(nums) {
    // Helper function to calculate the sum of digits of a number
    const digitSum = (num) => {
        // Convert to string, remove negative sign, split into digits, and sum them
        return Math.abs(num).toString().split('').reduce((sum, digit) => sum + parseInt(digit), 0);
    };

    // Create an array of objects with the original index and the number
    const indexedNums = nums.map((num, index) => ({ num, index }));

    // Sort based on the sum of digits, then by original index
    indexedNums.sort((a, b) => {
        const sumA = digitSum(a.num);
        const sumB = digitSum(b.num);
        if (sumA !== sumB) {
            return sumA - sumB;
        } else {
            return a.index - b.index;
        }
    });

    // Extract the sorted numbers
    return indexedNums.map(item => item.num);
}
