function get_max_triples(n) {
    // Generate the array a where a[i] = i*i - i + 1 for i from 1 to n
    const a = [];
    for (let i = 1; i <= n; i++) {
        a.push(i * i - i + 1);
    }

    // Count the number of triples (i, j, k) with i < j < k such that a[i] + a[j] + a[k] is divisible by 3
    let count = 0;

    // To optimize, we can work with remainders modulo 3
    const rem0 = []; // indices where a[i] % 3 === 0
    const rem1 = []; // indices where a[i] % 3 === 1
    const rem2 = []; // indices where a[i] % 3 === 2

    for (let i = 0; i < n; i++) {
        const r = a[i] % 3;
        if (r === 0) rem0.push(i);
        else if (r === 1) rem1.push(i);
        else rem2.push(i);
    }

    // We need to count triples (i, j, k) with i < j < k such that:
    // a[i] + a[j] + a[k] ≡ 0 (mod 3)
    // The possible combinations of remainders are:
    // (0, 0, 0), (1, 1, 1), (2, 2, 2), (0, 1, 2)

    // For (0, 0, 0): choose any 3 from rem0
    let c = rem0.length;
    if (c >= 3) {
        count += c * (c - 1) * (c - 2) / 6;
    }

    // For (1, 1, 1): choose any 3 from rem1
    c = rem1.length;
    if (c >= 3) {
        count += c * (c - 1) * (c - 2) / 6;
    }

    // For (2, 2, 2): choose any 3 from rem2
    c = rem2.length;
    if (c >= 3) {
        count += c * (c - 1) * (c - 2) / 6;
    }

    // For (0, 1, 2): choose one from each
    count += rem0.length * rem1.length * rem2.length;

    return count;
}
