function bf(planet1, planet2) {
    const planets = ["Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"];

    // Check if both planets are valid
    if (!planets.includes(planet1) || !planets.includes(planet2)) {
        return [];
    }

    const idx1 = planets.indexOf(planet1);
    const idx2 = planets.indexOf(planet2);

    // If they are the same, return empty array (no planets between them)
    if (idx1 === idx2) {
        return [];
    }

    // Determine start and end indices
    const start = Math.min(idx1, idx2);
    const end = Math.max(idx1, idx2);

    // Return planets strictly between start and end
    return planets.slice(start + 1, end);
}
