function do_algebra(operator, operand) {
    // We need to evaluate the expression following standard operator precedence
    // But the problem seems to imply left-to-right evaluation based on the example?
    // Let's check: 2 + 3 * 4 - 5 = 9
    // Standard precedence: 2 + (3*4) - 5 = 2 + 12 - 5 = 9. Yes, standard precedence works.

    // However, we need to handle floor division specially.
    // Let's implement a simple parser that respects operator precedence.

    const ops = {
        '+': (a, b) => a + b,
        '-': (a, b) => a - b,
        '*': (a, b) => a * b,
        '//': (a, b) => Math.floor(a / b),
        '**': (a, b) => Math.pow(a, b)
    };

    // We'll use two stacks: one for values and one for operators
    const values = [];
    const opStack = [];

    // Helper function to apply an operator
    const applyOp = (op, b, a) => {
        if (op === '//') {
            return Math.floor(a / b);
        } else if (op === '+') {
            return a + b;
        } else if (op === '-') {
            return a - b;
        } else if (op === '*') {
            return a * b;
        } else if (op === '**') {
            return Math.pow(a, b);
        }
    };

    // Helper function to determine precedence
    const precedence = (op) => {
        if (op === '+' || op === '-') return 1;
        if (op === '*' || op === '//') return 2;
        if (op === '**') return 3;
        return 0;
    };

    // Helper function to process operators with higher or equal precedence
    const processOp = () => {
        const op = opStack.pop();
        const b = values.pop();
        const a = values.pop();
        values.push(applyOp(op, b, a));
    };

    for (let i = 0; i < operator.length; i++) {
        // Push the first operand
        if (i === 0) {
            values.push(operand[0]);
        }

        const op = operator[i];

        // While there is an operator in the stack with greater or equal precedence
        while (opStack.length > 0 && precedence(opStack[opStack.length - 1]) >= precedence(op)) {
            processOp();
        }

        opStack.push(op);
        values.push(operand[i + 1]);
    }

    // Process remaining operators
    while (opStack.length > 0) {
        processOp();
    }

    return values[0];
}
