function separate_paren_groups(paren_string) {
    // Remove spaces
    const cleaned = paren_string.replace(/\s/g, '');

    const groups = [];
    let currentGroup = '';
    let depth = 0;

    for (const char of cleaned) {
        if (char === '(') {
            depth++;
            currentGroup += char;
        } else if (char === ')') {
            depth--;
            currentGroup += char;
            if (depth === 0) {
                groups.push(currentGroup);
                currentGroup = '';
            }
        }
    }

    return groups;
}
