    const mean = sum / numbers.length;

    // Calculate the mean absolute deviation
    const absDiffs = numbers.map(val => Math.abs(val - mean));
    const mad = absDiffs.reduce((acc, val) => acc + val, 0) / numbers.length;

    return mad;
}
