function factorize(n) {
    const factors = [];

    // Handle 2 separately to allow skipping even numbers later
    while (n % 2 === 0) {
        factors.push(2);
        n /= 2;
    }

    // Check odd factors from 3 upwards
    for (let i = 3; i * i <= n; i += 2) {
        while (n % i === 0) {
            factors.push(i);
            n /= i;
        }
    }

    // If n is a prime number greater than 2
    if (n > 2) {
        factors.push(n);
    }

    return factors;
}
