function circular_shift(x, shift) {
    const digits = String(x).split('');
    const n = digits.length;

    if (shift > n) {
        return digits.reverse().join('');
    }

    // Right circular shift by shift positions
    const effectiveShift = shift % n;
    if (effectiveShift === 0) {
        return digits.join('');
    }

    // Right shift: last 'effectiveShift' elements move to front
    const shifted = digits.slice(n - effectiveShift).concat(digits.slice(0, n - effectiveShift));
    return shifted.join('');
}
