function is_multiply_prime(a) {
    if (a < 2 || a >= 100) {
        return false;
    }

    // Helper function to check if a number is prime
    function isPrime(n) {
        if (n < 2) return false;
        if (n === 2) return true;
        if (n % 2 === 0) return false;
        for (let i = 3; i <= Math.sqrt(n); i += 2) {
            if (n % i === 0) return false;
        }
        return true;
    }

    // Find all prime factors of a
    let primeFactors = [];
    let num = a;

    // Check for factor 2
    while (num % 2 === 0) {
        primeFactors.push(2);
        num /= 2;
    }

    // Check for odd factors
    for (let i = 3; i <= Math.sqrt(num); i += 2) {
        while (num % i === 0) {
            primeFactors.push(i);
            num /= i;
        }
    }

    // If num is still greater than 1, then it's a prime factor
    if (num > 1) {
        primeFactors.push(num);
    }

    // Check if there are exactly 3 prime factors
    return primeFactors.length === 3;
}
