function is_simple_power(x, n) {
    // Handle edge cases
    if (x === 1) {
        return true;
    }

    // If n is 0 or 1, handle specially
    if (n === 0) {
        return x === 0 || x === 1;
    }

    if (n === 1) {
        return x === 1;
    }

    // If n is negative, we need to check if x can be represented as n^k for some integer k
    // For simplicity, let's assume we're dealing with positive integers based on examples

    // Handle negative base cases
    if (n < 0) {
        // If x is also negative or positive, we need to check powers
        // Let's work with absolute values and track sign
        let absN = Math.abs(n);
        let absX = Math.abs(x);

        if (absX === 1) {
            return true;
        }

        let power = 1;
        let i = 0;
        while (power < absX) {
            power *= absN;
            i++;
            if (power === absX) {
                // Check if the sign is correct
                // If n is negative, n^i should equal x
                // If i is even, n^i is positive; if i is odd, n^i is negative
                if ((i % 2 === 0 && x > 0) || (i % 2 !== 0 && x < 0)) {
                    return true;
                }
            }
        }

        return power === absX && ((i % 2 === 0 && x > 0) || (i % 2 !== 0 && x < 0));
    }

    // For positive n
    if (n <= 1) {
        return x === 1;
    }

    let power = 1;
    while (power < x) {
        power *= n;
    }

    return power === x;
}
