```javascript
function iscube(a) {
    if (a === 0) return true;

    // Calculate the cube root
    let cubeRoot = Math.round(Math.pow(Math.abs(a), 1/3));

    // Check both cubeRoot and cubeRoot-1, cubeRoot+1 due to floating point precision
    for (let r of [cubeRoot - 1, cubeRoot, cubeRoot + 1]) {
        if (r * r * r === Math.abs(a)) {
            return a >= 0;
        }
    }

    // For negative numbers, check if the cube root is negative
    if (a < 0) {
        for (let r of [-(cubeRoot - 1), -cubeRoot, -(cubeRoot + 1)]) {
            if (r * r * r === a) {
                return true;
            }
        }
    }

    return false;
}
