```javascript
function decimal_to_binary(decimal) {
    if (decimal === 0) {
        return "db0db";
    }

    let binary = "";
    let num = decimal;

    while (num > 0) {
        binary = (num % 2) + binary;
        num = Math.floor(num / 2);
    }

    return "db" + binary + "db";
}
