function prime_length(string) {
    const len = string.length;

    if (len < 2) {
        return false;
    }

    if (len === 2) {
        return true;
    }

    if (len % 2 === 0) {
        return false;
    }

    for (let i = 3; i <= Math.sqrt(len); i += 2) {
        if (len % i === 0) {
            return false;
        }
    }

    return true;
}
