```javascript
function solve(N) {
    // Calculate the sum of digits of N
    let sum = 0;
    let num = N;
    while (num > 0) {
        sum += num % 10;
        num = Math.floor(num / 10);
    }

    // Convert the sum to binary and return as a string
    return sum.toString(2);
}
