```javascript
function anti_shuffle(s) {
    // Split the string into words, preserving spaces and punctuation attached to words
    // We need to maintain the exact structure of spaces and word boundaries

    // Approach: split by space to get tokens, but we need to handle multiple spaces correctly
    // Actually, let's use a regex to split while keeping delimiters, or process character by character

    // Better approach: split into words considering that words are sequences of non-space characters
    // separated by one or more spaces. We need to preserve the exact whitespace pattern.

    // Let's split the string into an array of [word, space] pairs
    const result = [];
    let i = 0;
    const len = s.length;

    while (i < len) {
        // Collect a word (non-space characters)
        if (s[i] !== ' ') {
            let wordStart = i;
            while (i < len && s[i] !== ' ') {
                i++;
            }
            const word = s.slice(wordStart, i);
            // Sort the characters of the word by ASCII value
            const sortedWord = word.split('').sort((a, b) => a.charCodeAt(0) - b.charCodeAt(0)).join('');
            result.push(sortedWord);
        } else {
            // Collect consecutive spaces
            let spaceStart = i;
            while (i < len && s[i] === ' ') {
                i++;
            }
            const spaces = s.slice(spaceStart, i);
            result.push(spaces);
        }
    }

    return result.join('');
}
