function encrypt(s) {
    let result = '';
    for (let i = 0; i < s.length; i++) {
        const c = s[i];
        if (c >= 'a' && c <= 'z') {
            // Shift down by 4 places (2 * 2)
            let shifted = c.charCodeAt(0) - 'a'.charCodeAt(0) + 4;
            shifted = ((shifted % 26) + 26) % 26;
            result += String.fromCharCode(shifted + 'a'.charCodeAt(0));
        } else if (c >= 'A' && c <= 'Z') {
            let shifted = c.charCodeAt(0) - 'A'.charCodeAt(0) + 4;
            shifted = ((shifted % 26) + 26) % 26;
            result += String.fromCharCode(shifted + 'A'.charCodeAt(0));
        } else {
            result += c;
        }
    }
    return result;
}
```

