function any_int(x, y, z) {
    // Check if all numbers are integers
    if (!Number.isInteger(x) || !Number.isInteger(y) || !Number.isInteger(z)) {
        return false;
    }

    // Check if any number is equal to the sum of the other two
    return (x === y + z) || (y === x + z) || (z === x + y);
}
