function encode(message) {
    const vowels = 'aeiouAEIOU';
    const vowelMap = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    };

    let result = '';
    for (let char of message) {
        if (/[a-zA-Z]/.test(char)) {
            // Swap case
            let swapped;
            if (char >= 'a' && char <= 'z') {
                swapped = char.toUpperCase();
            } else {
                swapped = char.toLowerCase();
            }

            // If it's a vowel, replace with the letter 2 places ahead
            if (vowels.includes(swapped)) {
                result += vowelMap[swapped];
            } else {
                result += swapped;
            }
        } else {
            result += char;
        }
    }

    return result;
}
```
